/*jshint esversion: 6 */
const stackTrace = require('stack-trace');
const _ = require('lodash');
const path = require('path');
const mask = require('mask-pii')();
const Chronometer = require('express-chrono')({ header: true }).Chronometer;

let corebitPackages = [
    'aws-worker',
    'basic-url',
    'condition-evaluator',
    'express-authenticator',
    'express-authorizor',
    'express-badge',
    'express-cross-validator',
    'express-initializer',
    'express-paginator',
    'express-responser',
    'express-service-init',
    'logged-promise',
    'logged-request-promise',
    'mongoose-model-factory',
    'params-valid',
    'policy-evaluator',
    'sequelize-model-factory',
    'winstonize'
];

let logger;
let config;

module.exports.appStart = (_logger, _config) => {
    logger = _logger;
    config = _config;
};


module.exports.init = function (serviceInit) {
    if (!serviceInit || !serviceInit.requestId) throw new Error('Invalid request in logged promise');

    return function (data, promised, opt) {
        return new Promise(function (__resolver, __rejecter) {
            let chrono = new Chronometer({ format: 'ms', suffix: true });
            chrono.start();

            data = data || {};

            let functionName = opt ? opt.functionName || getFunctionName() : getFunctionName();

            let logRequestValue = JSON.stringify(data, mask);
            //a char is 2 bytes in JS
            if (config && logRequestValue && ((logRequestValue.length / 512) > config.maxLogSizeInKB)) {
                logRequestValue = '';
            }

            logger.info(`methodName:${functionName} callStep:started requestId:${serviceInit.requestId}`, logRequestValue);

            return new Promise(promised)
                .then(function (value) {
                    chrono.stop();

                    let logValue = "";

                    let hideLogsForResponse = false;
                    if (opt && opt.hideLogResponse) {
                        hideLogsForResponse = opt.hideLogResponse;
                    }
                    if (!hideLogsForResponse) {
                        logValue = JSON.stringify(value, mask);
                        //a char is 2 bytes in JS
                        if (config && logValue && ((logValue.length / 512) > config.maxLogSizeInKB)) {
                            hideLogsForResponse = true;
                        }
                    }

                    if (hideLogsForResponse)
                        logger.info(`methodName:${functionName} callStep:finished requestId:${serviceInit.requestId} elapsedTime:${chrono.toString()}`);
                    else
                        logger.info(`methodName:${functionName} callStep:finished requestId:${serviceInit.requestId}`, logValue, `elapsedTime:${chrono.toString()}`);
                    return __resolver(value);
                })
                .catch(function (err) {
                    chrono.stop();
                    const msg = `methodName:${functionName} callStep:errored requestId:${serviceInit.requestId} errorName:${err.name} errorStatus:${err.status} errorMessage:${err.message} errorStack:${err.stack} elapsedTime:${chrono.toString()}`;
                    if (err.customErrorType === 'Business') {
                        logger.info(msg);
                    } else {
                        logger.error(msg);
                    }
                    logger.debug(`methodName:${functionName} requestId:${serviceInit.requestId}`, err);
                    return __rejecter(err);
                });
        });
    };
};

let getPackageName = (fileName) => {

    if (!fileName)
        return null;

    if (!fileName.includes('node_modules'))
        return null;

    let tmpFileName = fileName.split(path.sep + 'node_modules' + path.sep);
    fileName = tmpFileName[1].split(path.sep)[0];

    if (corebitPackages.indexOf(fileName) > -1)
        return fileName;
    else
        return null;

};

function getFunctionName() {
    try {
        var stack = stackTrace.get();

        let longFunctionName;
        stack.some((value) => {

            let shortfunctionName = value.getFunctionName();
            let packageName = getPackageName(value.getFileName());
            let longFileName = value.getFileName();

            if (!shortfunctionName || !longFileName)
                return false;

            if (packageName && packageName != 'logged-promise') {
                longFunctionName = packageName + '.' + shortfunctionName;
                return true;
            }

            let shortFileName = _.join(_.last(longFileName.split(path.sep)).split('.').slice(0, -1), '.');
            //OGM: bu path resolutioni gozden gecirelim.
            //         stack.map(function(value){ return {functionName: value.getFunctionName(),fileName: _.last(value.getFileName().split(path.sep)), getColumnNumber: value.getColumnNumber(),getEvalOrigin: value.getEvalOrigin(),getFileName: value.getFileName(),getFunction: value.getFunction(),getFunctionName: value.getFunctionName(),getLineNumber: value.getLineNumber(),getMethodName: value.getMethodName(),getPosition: value.getPosition(),getScriptNameOrSourceURL: value.getScriptNameOrSourceURL(),getThis:value.getThis(),getTypeName: value.getTypeName(),isConstructor: value.isConstructor(), isEval: value.isEval(), isNative: value.isNative(), isToplevel: value.isToplevel()}}).filter(function(values){return !values.getFileName.includes('node_modules')})
            //ne yazik ki internal bir function call yapiyorsak module ici helper call vs gibi, helper function yerine main functionin ismini veriyor.
            if (longFileName.toLowerCase().includes(`${_.last(process.mainModule.filename.split(path.sep).slice(0, -2)).toLowerCase()}`) &&
                !longFileName.includes('node_modules') &&
                shortfunctionName) {
                longFunctionName = shortFileName + '.' + shortfunctionName;

                return true;
            }
        });

        return longFunctionName || 'logged-promise.getFunctionName';

    } catch (error) {
        return 'logged-promise.getFunctionName_err';
    }
}